-- ── Assign therapists to members ────────────────────────────
-- Build snapshots for all members that have events
DO $$
DECLARE
  m RECORD;
BEGIN
  FOR m IN SELECT DISTINCT member_id FROM inference_events LOOP
    PERFORM upsert_member_risk_snapshot(m.member_id);
  END LOOP;
END $$;

-- Assign therapists to member snapshots based on org
UPDATE member_risk_snapshots s
  SET therapist_id = 'thr_001'
  FROM members m
  WHERE s.member_id = m.id
    AND m.org_id = 'org_univ_maryland'
    AND (m.id % 2) = 0;
UPDATE member_risk_snapshots s
  SET therapist_id = 'thr_002'
  FROM members m
  WHERE s.member_id = m.id
    AND m.org_id = 'org_univ_maryland'
    AND (m.id % 2) = 1;
